parameters.content:
/**
 * Notification model — core types for the notification system.
 *
 * Architecture: Event-driven notifications via EventBus.
 * All notifications flow through: EventBus -> NotificationService -> NotificationAdapter(s).
 *
 * Constraints:
 * - All notification delivery must go through a NotificationAdapter implementation.
 * - All notification triggers must originate from EventBus events.
 * - NotificationService is the sole subscriber that translates events into notifications.
 */

/**
 * Supported notification channels. Each channel has a corresponding adapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app';

/**
 * Notification types correspond to the kinds of events that trigger notifications.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'user-updated';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID */
  id: string;
  /** What kind of notification this is */
  type: NotificationType;
  /** Which channel to deliver on */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject / title */
  subject: string;
  /** Notification body content */
  body: string;
  /** When the notification was created */
  createdAt: Date;
  /** Optional structured metadata for adapter-specific use */
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by adapters after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded */
  success: boolean;
  /** The notification that was sent */
  notificationId: string;
  /** Channel that handled delivery */
  channel: NotificationChannel;
  /** Timestamp of delivery attempt */
  deliveredAt: Date;
  /** Error message if delivery failed */
  error?: string;
}

/**
 * NotificationAdapter interface — the contract all notification delivery adapters must implement.
 *
 * Architecture constraint: Every notification channel (email, webhook, in-app, SMS, etc.)
 * must be implemented as a NotificationAdapter. The NotificationService dispatches to
 * adapters based on the notification's channel field.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create an adapter class implementing this interface in src/adapters/
 * 3. Register the adapter with NotificationService via registerAdapter()
 */

import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';

export interface NotificationAdapter {
  /** Which channel this adapter handles */
  readonly channel: NotificationChannel;

  /**
   * Send a notification. Adapters must handle their own error cases
   * and return a NotificationResult indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that records sent emails in-memory.
 * Replace the send() internals with a real email provider (SendGrid, SES, etc.)
 * while keeping the NotificationAdapter interface intact.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: EmailMessage = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    // Stub: store in memory instead of sending via SMTP/API
    this.sentEmails.push(email);

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
      deliveredAt: email.sentAt,
    };
  }

  /** Get all sent emails (for testing). */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /** Clear sent emails (for testing). */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — translates EventBus events into notification deliveries.
 *
 * Architecture: Pure event-driven pattern.
 * - Subscribes to EventBus events (the ONLY way notifications are triggered).
 * - Translates events into NotificationPayload objects.
 * - Dispatches payloads to registered NotificationAdapter implementations.
 *
 * Constraints:
 * - All notification triggers MUST come through EventBus.emit().
 * - All delivery MUST go through a NotificationAdapter (never send directly).
 * - To add a new channel: implement NotificationAdapter and call registerAdapter().
 * - To add a new notification trigger: subscribe to the event in registerEventHandlers().
 *
 * Depends on:
 * - EventBus (event system) for receiving all notification triggers
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private deliveryLog: NotificationResult[] = [];
  private notifications: NotificationPayload[] = [];

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a specific channel.
   * Only one adapter per channel is supported; registering a second replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all events that should trigger notifications.
   * This is the single place where event-to-notification mapping is defined.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      type: 'order-confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.send({
      type: 'order-status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.send({
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: `Welcome to TaskFlow Pro`,
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro! Your account has been created.`,
    });
  }

  /**
   * Build a NotificationPayload and dispatch to the appropriate adapter.
   */
  private async send(params: {
    type: NotificationPayload['type'];
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    metadata?: Record<string, unknown>;
  }): Promise<NotificationResult> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      createdAt: new Date(),
      metadata: params.metadata,
    };

    this.notifications.push(payload);

    const adapter = this.adapters.get(params.channel);
    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${params.channel}`);
      const result: NotificationResult = {
        success: false,
        notificationId: payload.id,
        channel: params.channel,
        deliveredAt: new Date(),
        error: `No adapter registered for channel: ${params.channel}`,
      };
      this.deliveryLog.push(result);
      return result;
    }

    const result = await adapter.send(payload);
    this.deliveryLog.push(result);
    this.logger.info(
      `Notification ${payload.id} via ${params.channel}: ${result.success ? 'delivered' : 'failed'}`,
    );
    return result;
  }

  /** Get all notification payloads that have been created. */
  getNotifications(): NotificationPayload[] {
    return [...this.notifications];
  }

  /** Get notifications for a specific recipient. */
  getNotificationsForRecipient(recipient: string): NotificationPayload[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /** Get the delivery log (results from adapter sends). */
  getDeliveryLog(): NotificationResult[] {
    return [...this.deliveryLog];
  }

  /** Get the count of sent notifications. */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /** Clear all notifications and delivery log (for testing). */
  clearNotifications(): void {
    this.notifications = [];
    this.deliveryLog = [];
  }
}

